export function getDemoSource(slug: string): string | undefined {
  return sourceMap[slug]?.demo;
}

export function getExampleSource(
  slug: string,
  exampleSlug: string,
): string | undefined {
  return sourceMap[slug]?.examples?.[exampleSlug];
}
